32 | @Command(name = "e2m", description = "Eclipse project to Maven project converter", version = "1.0", mixinStandardHelpOptions = true)
33 | public class Main implements Callable<Integer> {
34 | 
35 |     @Option(names = {"-g", "--groupId"}, required = false, description = "Maven groupId of the output project")
36 |     private String groupId;
37 | 
38 |     @Option(names = {"-a", "--artifactId"}, required = false, description = "Maven artifactId of the output project")
39 |     private String artifactId;
40 | 
41 |     @Option(names = {"-v", "--artifactVersion"}, required = false, description = "Maven version of the output project (default: 1.0-SNAPSHOT)")
42 |     private String artifactVersion;
43 |     private static final String DEFAULT_ARTIFACT_VERSION = "1.0-SNAPSHOT";
44 | 
45 |     @Parameters(index = "0", paramLabel = "<inputDir>", description = "Eclipse project directory to convert")
46 |     private File inputDir;
47 | 
48 |     @Parameters(index = "1", paramLabel = "<outputDir>", description = "Output directory for the Maven project")
49 |     private File outputDir;
50 | 
51 |     @Override
52 |     public Integer call() {
53 |         Path inputPath = inputDir.toPath();
54 | 
55 |         // 1. 入力ディレクトリの存在確認
56 |         if (!inputDir.isDirectory()) {
57 |             System.err.println("[ERROR] 入力ディレクトリが見つかりません: " + inputDir);
58 |             return 1;
59 |         }
60 |         if (!inputPath.resolve(".project").toFile().exists()) {
61 |             System.err.println("[ERROR] Eclipseプロジェクトではありません (.project ファイルが見つかりません): " + inputDir);
62 |             return 1;
63 |         }
64 |         if (outputDir.exists() && !outputDir.isDirectory()) {
65 |             System.err.println("[ERROR] 出力パスはディレクトリである必要があります: " + outputDir);
66 |             return 1;
67 |         }
68 | 
69 |         try {
70 |             // 2. Eclipseプロジェクト情報をパース
71 |             System.out.println("\n[1/5] Eclipseプロジェクトを解析中...");
72 |             EclipseProject eclipseProject = EclipseProjectParser.parse(inputPath);
73 |             System.out.println("  プロジェクト名: " + eclipseProject.projectName());
74 |             System.out.println("  種別: " + (eclipseProject.webProject() ? "Webプロジェクト (WTP)" : "Javaプロジェクト"));
75 |             System.out.println("  Javaソースバージョン: " + eclipseProject.javaSourceVersion());
76 |             System.out.println("  Javaターゲットバージョン: " + eclipseProject.javaTargetVersion());
77 |             if (eclipseProject.webProject()) {
78 |                 System.out.println("  Web仕様バージョン: " + eclipseProject.webVersion());
79 |             }
80 |             System.out.println("  ソースフォルダ: " + eclipseProject.sourceFolders());
81 |             if (eclipseProject.webProject()) {
82 |                 System.out.println("  Webコンテンツフォルダ: " + eclipseProject.webContentRoot());
83 |             }
84 |             System.out.println("  JARファイル数: " + eclipseProject.jarPaths().size());
85 | 
86 |             System.out.println("\n[2/5] 移行先のMavenプロジェクトを決定中...");
87 |             String defaultArtifactId = convertToArtifactId(eclipseProject.projectName());
88 |             if (groupId == null || groupId.isBlank()) {
89 |                 // オプション未指定の場合は対話的に入力を受け付ける
90 |                 try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
91 |                     groupId = promptIfAbsent(reader, "groupId", groupId, null);
92 |                     artifactId = promptIfAbsent(reader, "artifactId", artifactId, defaultArtifactId);
93 |                     artifactVersion = promptIfAbsent(reader, "artifactVersion", artifactVersion, DEFAULT_ARTIFACT_VERSION);
94 |                 }
95 |             } else {
96 |                 // 少なくとも--groupIdが指定されていれば，あとは空ならデフォルトを使用する
97 |                 if (artifactId == null || artifactId.isBlank()) {
98 |                     artifactId = defaultArtifactId;
99 |                 }
100 |                 if (artifactVersion == null || artifactId.isBlank()) {
101 |                     artifactVersion = DEFAULT_ARTIFACT_VERSION;
102 |                 }
103 |                 System.out.println("groupId: " + groupId);
104 |                 System.out.println("artifactId: " + artifactId);
105 |                 System.out.println("version: " + artifactVersion);
106 |             }
107 | 
108 |             // 出力先は outputDir/artifactId
109 |             Path outputPath = outputDir.toPath().resolve(artifactId);
110 |             if (outputPath.toFile().exists()) {
111 |                 System.err.println("[ERROR] 出力先ディレクトリがすでに存在しています: " + outputPath);
112 |                 return 1;
113 |             }
114 | 
115 |             System.out.println("\n=== e2m: Eclipse → Maven 変換開始 ===");
116 |             System.out.println("  入力: " + inputPath.toAbsolutePath());
117 |             System.out.println("  出力: " + outputPath.toAbsolutePath());
118 | 
119 |             // 3.(続き) JAR依存関係を解決
120 |             System.out.println("\n[3/5] JAR依存関係を解決中...");
121 |             List<MavenDependency> dependencies = DependencyResolver.resolve(eclipseProject.jarPaths(), inputPath);
122 |             long found = dependencies.stream().filter(d -> !"system".equals(d.scope())).count();
123 |             long system = dependencies.stream().filter(d -> "system".equals(d.scope())).count();
124 |             System.out.println("  Maven Central で見つかった依存: " + found + " 件");
125 |             System.out.println("  system スコープの依存: " + system + " 件");
126 | 
127 |             // 4. pom.xml を生成
128 |             System.out.println("\n[4/5] pom.xml を生成中...");
129 |             PomGenerator.generate(eclipseProject, dependencies, groupId, artifactId, artifactVersion, outputPath);
130 | 
131 |             // 5. ソース・Webコンテンツをコピー
132 |             System.out.println("\n[5/5] ソースファイルをコピー中...");
133 |             ProjectCopier.copy(eclipseProject, dependencies, inputPath, outputPath);
134 | 
135 |             System.out.println("\n=== 変換完了 ===");
136 |             System.out.println("出力先: " + outputPath.toAbsolutePath());
137 |             return 0;
138 | 
139 |         } catch (Exception e) {
140 |             System.err.println("[ERROR] 変換中にエラーが発生しました: " + e.getMessage());
141 |             e.printStackTrace(System.err);
142 |             return 2;
143 |         }
144 |     }
145 | 
146 |     /**
147 |      * 引数が null または空の場合にプロンプトを表示して入力を受け付ける。
148 |      * デフォルト値がある場合は "[default]" 形式で表示し、空入力でデフォルト値を採用する。
149 |      *
150 |      * @param reader       入力ストリーム
151 |      * @param name         項目名（表示用）
152 |      * @param value        コマンドライン引数の値（null または空の場合にプロンプト表示）
153 |      * @param defaultValue デフォルト値（null の場合はデフォルトなし）
154 |      * @return 確定した値
155 |      */
156 |     private static String promptIfAbsent(BufferedReader reader, String name,
157 |             String value, String defaultValue) throws Exception {
158 |         if (value != null && !value.isBlank()) {
159 |             return value;
160 |         }
161 |         while (true) {
162 |             if (defaultValue != null) {
163 |                 System.out.print(name + " [" + defaultValue + "]: ");
164 |             } else {
165 |                 System.out.print(name + ": ");
166 |             }
167 |             System.out.flush();
168 |             String line = reader.readLine();
169 |             if (line == null) {
170 |                 // EOF（パイプ等）の場合はデフォルト値を使用
171 |                 return defaultValue != null ? defaultValue : "";
172 |             }
173 |             String trimmed = line.trim();
174 |             if (trimmed.isEmpty()) {
175 |                 if (defaultValue != null) {
176 |                     return defaultValue;
177 |                 }
178 |                 System.err.println("  値を入力してください。");
179 |                 continue;
180 |             }
181 |             return trimmed;
182 |         }
183 |     }
184 | 
185 |     // artifactIdとして許可する文字（半角英数字、ハイフン、アンダースコア）以外にマッチする正規表現
186 |     private static final Pattern INVALID_CHARS = Pattern.compile("[^a-z0-9\\-_]");
187 | 
188 |     // キャメルケースの境界（大文字の前）にマッチする正規表現
189 |     private static final Pattern CAMEL_CASE_BOUNDARY = Pattern.compile("(?<=[a-z0-9])(?=[A-Z])");
190 | 
191 |     /**
192 |      * プロジェクト名からMavenのartifactIdとして利用可能な文字列を生成します。
193 |      *
194 |      * @param projectName プロジェクト名
195 |      * @return artifactId用文字列
196 |      */
197 |     public static String convertToArtifactId(String projectName) {
198 |         if (projectName == null || projectName.isBlank()) {
199 |             return "default-artifact";
200 |         }
201 | 
202 |         // 1. パッケージ名が含まれている場合（完全限定名）、最後のクラス名部分だけを抽出
203 |         String simpleName = projectName.substring(projectName.lastIndexOf('.') + 1);
204 | 
205 |         // 2. キャメルケース（OrderManager -> Order-Manager）をハイフン区切りに変換
206 |         String kebabCase = CAMEL_CASE_BOUNDARY.matcher(simpleName).replaceAll("-");
207 | 
208 |         // 3. すべて小文字に変換
209 |         String lowerCase = kebabCase.toLowerCase();
210 | 
211 |         // 4. artifactIdとして使えない文字（日本語や特殊記号など）を完全に除去
212 |         String sanitized = INVALID_CHARS.matcher(lowerCase).replaceAll("");
213 | 
214 |         // 5. 連続したハイフンやアンダースコアを綺麗に整理
215 |         sanitized = sanitized.replaceAll("[-_]{2,}", "-");
216 | 
217 |         // 6. 先頭や末尾にあるハイフン・アンダースコアを除去
218 |         sanitized = sanitized.replaceAll("^[-_]+|[-_]+$", "");
219 | 
220 |         // すべての文字が削られて空になった場合のフォールバック
221 |         return sanitized.isBlank() ? "converted-artifact" : sanitized;
222 |     }
223 | 
224 |     public static void main(String[] args) {
225 |         System.exit(new CommandLine(new Main()).execute(args));
226 |     }
227 | }
