33 | /**
34 |  * Eclipseの.classpathに記載されたJARファイルのSHA1ハッシュを計算し、
35 |  * Maven Central REST APIで依存関係情報を検索するクラス。
36 |  */
37 | public class DependencyResolver {
38 | 
39 |     private static final String MAVEN_SEARCH_URL =
40 |             "https://search.maven.org/solrsearch/select?q=1:%s&rows=1&wt=json";
41 | 
42 | 
43 |     private final HttpClient httpClient;
44 | 
45 |     public DependencyResolver() {
46 |         this.httpClient = HttpClient.newBuilder()
47 |                 .connectTimeout(Duration.ofSeconds(10))
48 |                 .build();
49 |     }
50 | 
51 |     /**
52 |      * JARが置かれたディレクトリパスのリストを受け取り、Maven依存関係リストに解決して返す。
53 |      * 各ディレクトリに含まれる全ての {@code .jar} ファイルについて解決を行う。
54 |      *
55 |      * @param jarPaths Eclipseの.classpathから取得したディレクトリパス文字列のリスト
56 |      * @param inputDir Eclipseプロジェクトのルートディレクトリ（相対パス解決の基準）
57 |      * @return 解決済みの {@link MavenDependency} リスト
58 |      */
59 |     public static List<MavenDependency> resolve(List<String> jarPaths, Path inputDir) {
60 |         DependencyResolver resolver = new DependencyResolver();
61 |         List<MavenDependency> results = new ArrayList<>();
62 |         for (String jarPath : jarPaths) {
63 |             Path dir = Path.of(jarPath).isAbsolute()
64 |                     ? Path.of(jarPath)
65 |                     : inputDir.resolve(jarPath);
66 |             if (!Files.isDirectory(dir)) {
67 |                 continue;
68 |             }
69 |             try (var stream = Files.list(dir)) {
70 |                 stream.filter(p -> p.getFileName().toString().endsWith(".jar"))
71 |                       .sorted()
72 |                       .forEach(p -> results.add(resolver.resolveJar(p.toString(), inputDir)));
73 |             } catch (IOException e) {
74 |                 System.err.println("  [WARN] ディレクトリの読み取りに失敗しました: " + dir);
75 |             }
76 |         }
77 |         return results;
78 |     }
79 | 
80 |     /**
81 |      * 1つのJARパスを解決する。
82 |      */
83 |     private MavenDependency resolveJar(String jarPath, Path inputDir) {
84 |         Path path = Path.of(jarPath).isAbsolute()
85 |                 ? Path.of(jarPath)
86 |                 : inputDir.resolve(jarPath);
87 | 
88 |         String jarFileName = path.getFileName().toString();
89 |         // 拡張子なしのベース名
90 |         String baseName = jarFileName.endsWith(".jar")
91 |                 ? jarFileName.substring(0, jarFileName.length() - 4)
92 |                 : jarFileName;
93 | 
94 |         System.out.println("  Resolving: " + jarFileName + " ...");
95 | 
96 |         if (!Files.exists(path)) {
97 |             System.err.println("  [WARN] JARファイルが見つかりません: " + path
98 |                     + " → systemスコープとして扱います");
99 |             System.out.println("  → not found (system scope): " + jarFileName);
100 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", jarPath);
101 |         }
102 | 
103 |         String sha1;
104 |         try {
105 |             sha1 = computeSha1(path);
106 |         } catch (Exception e) {
107 |             System.err.println("  [ERROR] SHA1計算に失敗しました: " + path + " → " + e.getMessage());
108 |             System.out.println("  → SHA1 error (system scope): " + jarFileName);
109 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
110 |         }
111 | 
112 |         try {
113 |             String json = callMavenCentralApi(sha1);
114 |             return parseResponse(json, baseName, path.toAbsolutePath().toString());
115 |         } catch (Exception e) {
116 |             System.err.println("  [ERROR] Maven Central API呼び出しに失敗しました: " + jarFileName
117 |                     + " → " + e.getMessage());
118 |             System.out.println("  → API error (system scope): " + jarFileName);
119 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
120 |         }
121 |     }
122 | 
123 |     /**
124 |      * JARファイルのSHA1ハッシュを小文字16進数文字列として計算する。
125 |      */
126 |     static String computeSha1(Path file) throws Exception {
127 |         MessageDigest digest = MessageDigest.getInstance("SHA-1");
128 |         byte[] bytes = Files.readAllBytes(file);
129 |         byte[] hash = digest.digest(bytes);
130 |         StringBuilder sb = new StringBuilder(hash.length * 2);
131 |         for (byte b : hash) {
132 |             sb.append(String.format("%02x", b));
133 |         }
134 |         return sb.toString();
135 |     }
136 | 
137 |     /**
138 |      * Maven Central Search APIを呼び出してJSONレスポンスを返す。
139 |      * テスト用にprotectedとして定義し、サブクラスでオーバーライド可能にする。
140 |      */
141 |     protected String callMavenCentralApi(String sha1) throws IOException, InterruptedException {
142 |         String url = String.format(MAVEN_SEARCH_URL, sha1);
143 |         HttpRequest request = HttpRequest.newBuilder()
144 |                 .uri(URI.create(url))
145 |                 .timeout(Duration.ofSeconds(10))
146 |                 .GET()
147 |                 .build();
148 |         HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
149 |         return response.body();
150 |     }
151 | 
152 |     // private static final Pattern GROUP_ID_PATTERN    = Pattern.compile("\"g\"\\s*:\\s*\"([^\"]+)\"");
153 |     // private static final Pattern ARTIFACT_ID_PATTERN = Pattern.compile("\"a\"\\s*:\\s*\"([^\"]+)\"");
154 |     // private static final Pattern VERSION_PATTERN     = Pattern.compile("\"latestVersion\"\\s*:\\s*\"([^\"]+)\"");
155 |     // private static final Pattern NUM_FOUND_PATTERN   = Pattern.compile("\"numFound\"\\s*:\\s*(\\d+)");
156 |     private static final Pattern GROUP_ID_PATTERN    = Pattern.compile("\"g\":\"([^\"]+)\"");
157 |     private static final Pattern ARTIFACT_ID_PATTERN = Pattern.compile("\"a\":\"([^\"]+)\"");
158 |     private static final Pattern VERSION_PATTERN     = Pattern.compile("\"v\":\"([^\"]+)\"");
159 |     private static final Pattern NUM_FOUND_PATTERN   = Pattern.compile("\"numFound\"\\s*:\\s*(\\d+)");
160 | 
161 |     /**
162 |      * Maven Central APIのJSONレスポンスをパースしてMavenDependencyを返す。
163 |      */
164 |     private static MavenDependency parseResponse(String json, String baseName, String absolutePath) {
165 |         // numFound:0 なら見つからなかった
166 |         Matcher numFoundMatcher = NUM_FOUND_PATTERN.matcher(json);
167 |         if (numFoundMatcher.find()) {
168 |             int numFound = Integer.parseInt(numFoundMatcher.group(1));
169 |             if (numFound == 0) {
170 |                 System.out.println("  → not found in Maven Central (system scope): " + baseName);
171 |                 return new MavenDependency(baseName, baseName, "0.0.0", "system", absolutePath);
172 |             }
173 |         }
174 | 
175 |         Matcher gMatcher = GROUP_ID_PATTERN.matcher(json);
176 |         Matcher aMatcher = ARTIFACT_ID_PATTERN.matcher(json);
177 |         Matcher vMatcher = VERSION_PATTERN.matcher(json);
178 | 
179 |         if (gMatcher.find() && aMatcher.find() && vMatcher.find()) {
180 |             String groupId    = gMatcher.group(1);
181 |             String artifactId = aMatcher.group(1);
182 |             String version    = vMatcher.group(1);
183 |             System.out.println("  → found: " + groupId + ":" + artifactId + ":" + version);
184 |             return new MavenDependency(groupId, artifactId, version, null, null);
185 |         }
186 | 
187 |         // パースに失敗した場合もsystemスコープ
188 |         System.err.println("  [WARN] Maven Central APIレスポンスのパースに失敗しました: " + baseName);
189 |         System.out.println("  → parse error (system scope): " + baseName);
190 |         return new MavenDependency(baseName, baseName, "0.0.0", "system", absolutePath);
191 |     }
192 | }
