33 | /**
34 |  * EclipseProject情報と依存関係リストからMavenのpom.xmlを生成するクラス。
35 |  */
36 | public class PomGenerator {
37 | 
38 |     private static final String MAVEN_COMPILER_PLUGIN_VERSION = "3.15.0";
39 |     private static final String MAVEN_WAR_PLUGIN_VERSION = "3.5.1";
40 | 
41 |     private PomGenerator() {}
42 | 
43 |     /**
44 |      * pom.xmlを生成して出力ディレクトリに保存する。
45 |      *
46 |      * @param eclipseProject パース済みEclipseプロジェクト情報
47 |      * @param dependencies   解決済み依存関係リスト
48 |      * @param groupId        生成するpom.xmlのgroupId
49 |      * @param artifactId     生成するpom.xmlのartifactId
50 |      * @param version        生成するpom.xmlのversion
51 |      * @param outputDir      出力ディレクトリ
52 |      * @throws Exception XML生成またはファイル書き込みに失敗した場合
53 |      */
54 |     public static void generate(
55 |             EclipseProject eclipseProject,
56 |             List<MavenDependency> dependencies,
57 |             String groupId,
58 |             String artifactId,
59 |             String version,
60 |             Path outputDir) throws Exception {
61 | 
62 |         DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
63 |         DocumentBuilder db = dbf.newDocumentBuilder();
64 |         Document doc = db.newDocument();
65 | 
66 |         // <project>
67 |         Element project = doc.createElement("project");
68 |         project.setAttribute("xmlns", "http://maven.apache.org/POM/4.0.0");
69 |         project.setAttribute("xmlns:xsi", "http://www.w3.org/2001/XMLSchema-instance");
70 |         project.setAttribute("xsi:schemaLocation",
71 |                 "http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd");
72 |         doc.appendChild(project);
73 | 
74 |         addTextElement(doc, project, "modelVersion", "4.0.0");
75 |         addTextElement(doc, project, "groupId", groupId);
76 |         addTextElement(doc, project, "artifactId", artifactId);
77 |         addTextElement(doc, project, "version", version);
78 | 
79 |         if (eclipseProject.webProject()) {
80 |             addTextElement(doc, project, "packaging", "war");
81 |         }
82 | 
83 |         // <properties>
84 |         String javaSourceVersion = eclipseProject.javaSourceVersion();
85 |         String javaTargetVersion = eclipseProject.javaTargetVersion();
86 |         Element properties = doc.createElement("properties");
87 |         addTextElement(doc, properties, "project.build.sourceEncoding", "UTF-8");
88 |         addTextElement(doc, properties, "maven.compiler.source", javaSourceVersion);
89 |         addTextElement(doc, properties, "maven.compiler.target", javaTargetVersion);
90 |         project.appendChild(properties);
91 | 
92 |         // <dependencies>
93 |         boolean hasDependencies = !dependencies.isEmpty() || eclipseProject.webProject();
94 |         if (hasDependencies) {
95 |             Element deps = doc.createElement("dependencies");
96 |             for (MavenDependency dep : dependencies) {
97 |                 Element dependency = doc.createElement("dependency");
98 |                 addTextElement(doc, dependency, "groupId", dep.groupId());
99 |                 addTextElement(doc, dependency, "artifactId", dep.artifactId());
100 |                 addTextElement(doc, dependency, "version", dep.version());
101 |                 if (dep.scope() != null && !dep.scope().isEmpty()) {
102 |                     addTextElement(doc, dependency, "scope", dep.scope());
103 |                 }
104 |                 if (dep.systemPath() != null) {
105 |                     // system スコープの JAR は libs/ にコピーされるため ${project.basedir}/libs/<ファイル名> で参照
106 |                     String fileName = Path.of(dep.systemPath()).getFileName().toString();
107 |                     addTextElement(doc, dependency, "systemPath",
108 |                             "${project.basedir}/libs/" + fileName);
109 |                 }
110 |                 deps.appendChild(dependency);
111 |             }
112 |             // webProject の場合は Java EE / Jakarta EE API を provided で追加
113 |             if (eclipseProject.webProject() && eclipseProject.webVersion() != null) {
114 |                 String webVersion = eclipseProject.webVersion();
115 |                 boolean tooOld = webVersion.startsWith("2");
116 |                 String resolvedVersion = tooOld ? "3.0" : webVersion;
117 |                 JavaEEVersion javaEE = JavaEEVersion.of(resolvedVersion);
118 |                 Element dependency = doc.createElement("dependency");
119 |                 if (tooOld) {
120 |                     deps.appendChild(doc.createComment(
121 |                             " WARNING: Servlet " + webVersion + " は古すぎるため対応する javaee-api dependency が存在しません。"
122 |                             + " Java EE 6 (javaee-api:6.0) に置き換えています。マイグレーションが必要です。 "));
123 |                 }
124 |                 addTextElement(doc, dependency, "groupId", javaEE.getGroupId());
125 |                 addTextElement(doc, dependency, "artifactId", javaEE.getArtifactId());
126 |                 addTextElement(doc, dependency, "version", javaEE.getVersion());
127 |                 addTextElement(doc, dependency, "scope", "provided");
128 |                 deps.appendChild(dependency);
129 |             }
130 |             project.appendChild(deps);
131 |         }
132 | 
133 |         // <build><plugins><plugin> maven-compiler-plugin
134 |         Element build = doc.createElement("build");
135 |         Element plugins = doc.createElement("plugins");
136 |         Element plugin = doc.createElement("plugin");
137 |         addTextElement(doc, plugin, "groupId", "org.apache.maven.plugins");
138 |         addTextElement(doc, plugin, "artifactId", "maven-compiler-plugin");
139 |         addTextElement(doc, plugin, "version", MAVEN_COMPILER_PLUGIN_VERSION);
140 |         plugins.appendChild(plugin);
141 |         // webProject の場合は maven-war-plugin を追加
142 |         if (eclipseProject.webProject()) {
143 |             Element warPlugin = doc.createElement("plugin");
144 |             addTextElement(doc, warPlugin, "groupId", "org.apache.maven.plugins");
145 |             addTextElement(doc, warPlugin, "artifactId", "maven-war-plugin");
146 |             addTextElement(doc, warPlugin, "version", MAVEN_WAR_PLUGIN_VERSION);
147 |             Element configuration = doc.createElement("configuration");
148 |             addTextElement(doc, configuration, "failOnMissingWebXml", "false");
149 |             warPlugin.appendChild(configuration);
150 |             plugins.appendChild(warPlugin);
151 |         }
152 |         build.appendChild(plugins);
153 |         project.appendChild(build);
154 | 
155 |         // XMLをファイルに書き出す
156 |         Files.createDirectories(outputDir);
157 |         TransformerFactory tf = TransformerFactory.newInstance();
158 |         Transformer transformer = tf.newTransformer();
159 |         transformer.setOutputProperty(OutputKeys.INDENT, "yes");
160 |         transformer.setOutputProperty(OutputKeys.ENCODING, "UTF-8");
161 |         transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");
162 | 
163 |         Path pomPath = outputDir.resolve("pom.xml");
164 |         transformer.transform(new DOMSource(doc), new StreamResult(pomPath.toFile()));
165 | 
166 |         System.out.println("Generated: " + pomPath);
167 |     }
168 | 
169 |     private static void addTextElement(Document doc, Element parent, String tagName, String text) {
170 |         Element el = doc.createElement(tagName);
171 |         el.appendChild(doc.createTextNode(text));
172 |         parent.appendChild(el);
173 |     }
174 | }
