package com.ibm.jp.automation.e2m;

import java.io.IOException;
import java.io.OutputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.attribute.BasicFileAttributes;
import java.time.Instant;
import java.time.LocalDateTime;
import java.time.ZoneId;
import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.zip.ZipEntry;
import java.util.zip.ZipOutputStream;

/**
 * デバッグ情報を ZIP アーカイブとして出力するクラス。
 *
 * <p>出力内容:</p>
 * <ul>
 *   <li>Eclipseプロジェクトの {@code .project}，{@code .classpath}，{@code .factorypath}，
 *       {@code .settings/} 以下の全ファイル</li>
 *   <li>Eclipseプロジェクト内の全ファイル一覧（名前・サイズ・日付）</li>
 *   <li>調べたJARのファイル名・SHA1・APIレスポンスJSON</li>
 *   <li>生成したMavenプロジェクトの {@code pom.xml}</li>
 *   <li>生成したMavenプロジェクトの全ファイル一覧（名前・サイズ・日付）</li>
 * </ul>
 */
public class DebugArchiver {

    private static final DateTimeFormatter TIMESTAMP_FMT =
            DateTimeFormatter.ofPattern("yyyyMMdd_HHmmss");
    private static final DateTimeFormatter FILETIME_FMT =
            DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");

    private DebugArchiver() {}

    /**
     * デバッグ ZIP を生成して出力ディレクトリに保存する。
     *
     * @param inputDir   Eclipseプロジェクトのルートディレクトリ
     * @param outputDir  outputDir（artifactId を含まないトップレベルのディレクトリ）
     * @param mavenDir   生成したMavenプロジェクトのルートディレクトリ
     * @param jarRecords JAR解決情報のリスト
     * @throws IOException ZIP生成またはファイル書き込みに失敗した場合
     */
    public static void archive(Path inputDir, Path outputDir, Path mavenDir,
            List<DependencyResolver.JarResolutionRecord> jarRecords) throws IOException {

        String timestamp = LocalDateTime.now().format(TIMESTAMP_FMT);
        Path zipPath = outputDir.resolve("e2m_debug_" + timestamp + ".zip");
        Files.createDirectories(outputDir);

        System.out.println("\n[DEBUG] デバッグ情報を出力中: " + zipPath);

        try (OutputStream fos = Files.newOutputStream(zipPath);
             ZipOutputStream zos = new ZipOutputStream(fos, StandardCharsets.UTF_8)) {

            // ── 1. Eclipseプロジェクトのメタファイル ──────────────────────────
            addEclipseMetaFiles(zos, inputDir);

            // ── 2. Eclipseプロジェクトのファイル一覧 ──────────────────────────
            String eclipseFileListing = buildFileListing(inputDir, "eclipse-project");
            addText(zos, "eclipse_files.txt", eclipseFileListing);

            // ── 3. JAR解決情報 ────────────────────────────────────────────────
            if (jarRecords != null && !jarRecords.isEmpty()) {
                addText(zos, "jar_resolution.txt", buildJarResolutionText(jarRecords));
            }

            // ── 4. 生成したMavenプロジェクトのpom.xml ────────────────────────
            if (mavenDir != null) {
                Path pomFile = mavenDir.resolve("pom.xml");
                if (Files.isRegularFile(pomFile)) {
                    addFile(zos, pomFile, "pom.xml");
                }

                // ── 5. 生成したMavenプロジェクトのファイル一覧 ──────────────
                String mavenFileListing = buildFileListing(mavenDir, "maven-project");
                addText(zos, "maven_files.txt", mavenFileListing);
            }
        }

        System.out.println("[DEBUG] 出力完了: " + zipPath.toAbsolutePath());
    }

    // ── プライベートヘルパー ──────────────────────────────────────────────────

    /**
     * Eclipseプロジェクトのメタファイル（.project, .classpath, .factorypath,
     * .settings/ 以下全て）を ZIP に追加する。
     */
    private static void addEclipseMetaFiles(ZipOutputStream zos, Path inputDir) throws IOException {
        // 単一ファイル
        for (String name : new String[]{".project", ".classpath", ".factorypath"}) {
            Path file = inputDir.resolve(name);
            if (Files.isRegularFile(file)) {
                addFile(zos, file, "eclipse/" + name);
            }
        }
        // .settings/ ディレクトリ
        Path settingsDir = inputDir.resolve(".settings");
        if (Files.isDirectory(settingsDir)) {
            Files.walk(settingsDir)
                    .filter(Files::isRegularFile)
                    .sorted()
                    .forEach(p -> {
                        try {
                            String relative = inputDir.relativize(p).toString().replace('\\', '/');
                            addFile(zos, p, "eclipse/" + relative);
                        } catch (IOException e) {
                            throw new RuntimeException("ZIPへの追加に失敗しました: " + p, e);
                        }
                    });
        }
    }

    /**
     * 指定ディレクトリ以下の全ファイル・ディレクトリ一覧テキストを返す。
     * 形式: {@code <種別> <サイズ(bytes)> <更新日時> <パス>}
     */
    private static String buildFileListing(Path root, String label) throws IOException {
        StringBuilder sb = new StringBuilder();
        sb.append("# ").append(label).append(" : ").append(root.toAbsolutePath()).append("\n");
        sb.append(String.format("%-4s  %12s  %-19s  %s%n", "TYPE", "SIZE", "LAST_MODIFIED", "PATH"));
        sb.append("-".repeat(80)).append("\n");

        if (!Files.exists(root)) {
            sb.append("(ディレクトリが存在しません)\n");
            return sb.toString();
        }

        Files.walk(root)
                .sorted()
                .forEach(p -> {
                    try {
                        BasicFileAttributes attrs = Files.readAttributes(p, BasicFileAttributes.class);
                        String type = attrs.isDirectory() ? "DIR " : "FILE";
                        long size = attrs.isDirectory() ? 0L : attrs.size();
                        Instant instant = attrs.lastModifiedTime().toInstant();
                        String modified = LocalDateTime.ofInstant(instant, ZoneId.systemDefault())
                                .format(FILETIME_FMT);
                        String relative = root.relativize(p).toString().replace('\\', '/');
                        if (relative.isEmpty()) {
                            relative = ".";
                        }
                        sb.append(String.format("%-4s  %12d  %s  %s%n", type, size, modified, relative));
                    } catch (IOException e) {
                        sb.append("(読み取りエラー: ").append(p).append(")\n");
                    }
                });

        return sb.toString();
    }

    /**
     * JAR解決情報テキストを構築する。
     */
    private static String buildJarResolutionText(List<DependencyResolver.JarResolutionRecord> records) {
        StringBuilder sb = new StringBuilder();
        sb.append("# JAR Resolution Records\n");
        sb.append("# fileName / sha1 / API response JSON\n\n");
        for (DependencyResolver.JarResolutionRecord r : records) {
            sb.append("## ").append(r.fileName()).append("\n");
            sb.append("SHA1: ").append(r.sha1() != null ? r.sha1() : "(not computed)").append("\n");
            sb.append("JSON:\n").append(r.json() != null ? r.json() : "(no response)").append("\n\n");
        }
        return sb.toString();
    }

    /** ファイルを ZIP エントリとして追加する。 */
    private static void addFile(ZipOutputStream zos, Path file, String entryName) throws IOException {
        zos.putNextEntry(new ZipEntry(entryName));
        Files.copy(file, zos);
        zos.closeEntry();
    }

    /** 文字列テキストを ZIP エントリとして追加する。 */
    private static void addText(ZipOutputStream zos, String entryName, String text) throws IOException {
        byte[] bytes = text.getBytes(StandardCharsets.UTF_8);
        zos.putNextEntry(new ZipEntry(entryName));
        zos.write(bytes);
        zos.closeEntry();
    }
}

