59 |     public static List<MavenDependency> resolve(List<String> jarPaths, Path inputDir) {
60 |         DependencyResolver resolver = new DependencyResolver();
61 |         List<MavenDependency> results = new ArrayList<>();
62 |         for (String jarPath : jarPaths) {
63 |             Path dir = Path.of(jarPath).isAbsolute()
64 |                     ? Path.of(jarPath)
65 |                     : inputDir.resolve(jarPath);
66 |             if (!Files.isDirectory(dir)) {
67 |                 continue;
68 |             }
69 |             try (var stream = Files.list(dir)) {
70 |                 stream.filter(p -> p.getFileName().toString().endsWith(".jar"))
71 |                       .sorted()
72 |                       .forEach(p -> results.add(resolver.resolveJar(p.toString(), inputDir)));
73 |             } catch (IOException e) {
74 |                 System.err.println("  [WARN] ディレクトリの読み取りに失敗しました: " + dir);
75 |             }
76 |         }
77 |         return results;
