84 |         Path path = Path.of(jarPath).isAbsolute()
85 |                 ? Path.of(jarPath)
86 |                 : inputDir.resolve(jarPath);
87 | 
88 |         String jarFileName = path.getFileName().toString();
89 |         // 拡張子なしのベース名
90 |         String baseName = jarFileName.endsWith(".jar")
91 |                 ? jarFileName.substring(0, jarFileName.length() - 4)
92 |                 : jarFileName;
93 | 
94 |         System.out.println("  Resolving: " + jarFileName + " ...");
95 | 
96 |         if (!Files.exists(path)) {
97 |             System.err.println("  [WARN] JARファイルが見つかりません: " + path
98 |                     + " → systemスコープとして扱います");
99 |             System.out.println("  → not found (system scope): " + jarFileName);
100 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", jarPath);
101 |         }
102 | 
103 |         String sha1;
104 |         try {
105 |             sha1 = computeSha1(path);
106 |         } catch (Exception e) {
107 |             System.err.println("  [ERROR] SHA1計算に失敗しました: " + path + " → " + e.getMessage());
108 |             System.out.println("  → SHA1 error (system scope): " + jarFileName);
109 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
110 |         }
111 | 
112 |         try {
113 |             String json = callMavenCentralApi(sha1);
114 |             return parseResponse(json, baseName, path.toAbsolutePath().toString());
115 |         } catch (Exception e) {
116 |             System.err.println("  [ERROR] Maven Central API呼び出しに失敗しました: " + jarFileName
117 |                     + " → " + e.getMessage());
118 |             System.out.println("  → API error (system scope): " + jarFileName);
119 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
120 |         }
