126 |     static String computeSha1(Path file) throws Exception {
127 |         MessageDigest digest = MessageDigest.getInstance("SHA-1");
128 |         byte[] bytes = Files.readAllBytes(file);
129 |         byte[] hash = digest.digest(bytes);
130 |         StringBuilder sb = new StringBuilder(hash.length * 2);
131 |         for (byte b : hash) {
132 |             sb.append(String.format("%02x", b));
133 |         }
134 |         return sb.toString();
