142 |         String url = String.format(MAVEN_SEARCH_URL, sha1);
143 |         HttpRequest request = HttpRequest.newBuilder()
144 |                 .uri(URI.create(url))
145 |                 .timeout(Duration.ofSeconds(10))
146 |                 .GET()
147 |                 .build();
148 |         HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
149 |         return response.body();
