156 |     private static String promptIfAbsent(BufferedReader reader, String name,
157 |             String value, String defaultValue) throws Exception {
158 |         if (value != null && !value.isBlank()) {
159 |             return value;
160 |         }
161 |         while (true) {
162 |             if (defaultValue != null) {
163 |                 System.out.print(name + " [" + defaultValue + "]: ");
164 |             } else {
165 |                 System.out.print(name + ": ");
166 |             }
167 |             System.out.flush();
168 |             String line = reader.readLine();
169 |             if (line == null) {
170 |                 // EOF（パイプ等）の場合はデフォルト値を使用
171 |                 return defaultValue != null ? defaultValue : "";
172 |             }
173 |             String trimmed = line.trim();
174 |             if (trimmed.isEmpty()) {
175 |                 if (defaultValue != null) {
176 |                     return defaultValue;
177 |                 }
178 |                 System.err.println("  値を入力してください。");
179 |                 continue;
180 |             }
181 |             return trimmed;
182 |         }
