187 | 
188 |     // キャメルケースの境界（大文字の前）にマッチする正規表現
189 |     private static final Pattern CAMEL_CASE_BOUNDARY = Pattern.compile("(?<=[a-z0-9])(?=[A-Z])");
190 | 
191 |     /**
192 |      * プロジェクト名からMavenのartifactIdとして利用可能な文字列を生成します。
193 |      *
194 |      * @param projectName プロジェクト名
195 |      * @return artifactId用文字列
196 |      */
197 |     public static String convertToArtifactId(String projectName) {
198 |         if (projectName == null || projectName.isBlank()) {
199 |             return "default-artifact";
200 |         }
201 | 
202 |         // 1. パッケージ名が含まれている場合（完全限定名）、最後のクラス名部分だけを抽出
203 |         String simpleName = projectName.substring(projectName.lastIndexOf('.') + 1);
204 | 
205 |         // 2. キャメルケース（OrderManager -> Order-Manager）をハイフン区切りに変換
206 |         String kebabCase = CAMEL_CASE_BOUNDARY.matcher(simpleName).replaceAll("-");
207 | 
208 |         // 3. すべて小文字に変換
209 |         String lowerCase = kebabCase.toLowerCase();
210 | 
211 |         // 4. artifactIdとして使えない文字（日本語や特殊記号など）を完全に除去
212 |         String sanitized = INVALID_CHARS.matcher(lowerCase).replaceAll("");
213 | 
214 |         // 5. 連続したハイフンやアンダースコアを綺麗に整理
215 |         sanitized = sanitized.replaceAll("[-_]{2,}", "-");
216 | 
217 |         // 6. 先頭や末尾にあるハイフン・アンダースコアを除去
218 |         sanitized = sanitized.replaceAll("^[-_]+|[-_]+$", "");
219 | 
220 |         // すべての文字が削られて空になった場合のフォールバック
221 |         return sanitized.isBlank() ? "converted-artifact" : sanitized;
