    private static final Pattern INVALID_CHARS = Pattern.compile("[^a-z0-9\\-_]");

    // キャメルケースの境界（大文字の前）にマッチする正規表現
    private static final Pattern CAMEL_CASE_BOUNDARY = Pattern.compile("(?<=[a-z0-9])(?=[A-Z])");

