        if (version == null || version.isBlank()) {
            return UNKNOWN_VERSION;
        }
        String v = version.trim();

        // "1.x" 形式（例: "1.8"）
        if (v.startsWith("1.")) {
            try {
                int minor = Integer.parseInt(v.substring(2));
                if (minor < 0) {
                    return UNKNOWN_VERSION;
                }
                return new JavaVersion(minor, v);
            } catch (NumberFormatException e) {
                return UNKNOWN_VERSION;
            }
        }

        // 整数形式（例: "5", "11", "17"）
        try {
            int n = Integer.parseInt(v);
            if (n < 1) {
                return UNKNOWN_VERSION;
            }
            return new JavaVersion(n, v);
        } catch (NumberFormatException e) {
            return UNKNOWN_VERSION;
        }
    }

    /**
     * このインスタンスが {@link #UNKNOWN_VERSION} かどうかを返す。
     */
    public boolean isUnknown() {
        return this.value == -1;
    }

    /**
     * 内部的な整数バージョン番号を返す（例: "1.8" → 8、"17" → 17）。
     */
    public int toInt() {
        return value;
    }

    @Override
    public int compareTo(JavaVersion other) {
        return Integer.compare(this.value, other.value);
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof JavaVersion other)) return false;
        return this.value == other.value;
    }

    @Override
    public int hashCode() {
        return Integer.hashCode(value);
    }

    /** 元の文字列表現を返す（例: {@code "1.8"}、{@code "17"}）。 */
    @Override
    public String toString() {
        return original;
    }
}

